#!/bin/bash
# Тестовый скрипт для создания ордера и проверки сохранения в Google Sheets

set -e

# Определяем URL в зависимости от окружения
ENVIRONMENT="${1:-production}"
if [ "$ENVIRONMENT" == "staging" ] || [ "$ENVIRONMENT" == "minimal-stage" ]; then
  API_URL="https://stage.minimal.build.infra.1otc.cc"
else
  API_URL="https://1otc.cc"
fi

echo "🧪 Тестирование создания ордера на $API_URL"
echo "=========================================="
echo ""

# Генерируем уникальный email для теста
TEST_EMAIL="test-$(date +%s)@example.com"
TEST_ORDER_ID="TEST-$(date +%s)"

echo "📋 Параметры тестового ордера:"
echo "  Email: $TEST_EMAIL"
echo "  URL: $API_URL/api/create-order"
echo ""

# Создаем тестовый ордер
echo "🚀 Отправляем запрос на создание ордера..."
RESPONSE=$(curl -s -X POST "$API_URL/api/create-order" \
  -H "Content-Type: application/json" \
  -d "{
    \"paymentToken\": {
      \"symbol\": \"USDT\",
      \"network\": \"TRON\",
      \"networkName\": \"TRON\",
      \"decimals\": 6,
      \"priceUSD\": 1,
      \"minAmount\": 1,
      \"receivingAddress\": \"\",
      \"icon\": \"₮\",
      \"color\": \"#50AF95\"
    },
    \"paymentAmount\": 100,
    \"paymentAmountUSD\": 100,
    \"cantonAmount\": 130,
    \"cantonAddress\": \" time

echo "✅ Ответ получен!"
echo ""
echo "📋 Результат:"
echo "$RESPONSE" | jq '.' 2>/dev/null || echo "$RESPONSE"
echo ""

# Извлекаем orderId из ответа
ORDER_ID=$(echo "$RESPONSE" | jq -r '.orderId' 2>/dev/null)

if [ -n "$ORDER_ID" ] && [ "$ORDER_ID" != "null" ]; then
  echo "✅ Ордер успешно создан: $ORDER_ID"
  echo ""
  echo "⏳ Ждем 5 секунд для обработки в фоне..."
  sleep 5
  echo ""
  echo "📊 Проверьте Google Таблицу - ордер должен появиться в таблице"
  echo "   Order ID для поиска: $ORDER_ID"
  echo "   Email для поиска: $TEST_EMAIL"
else
  echo "❌ Ошибка при создании ордера!"
  echo "$RESPONSE"
  exit 1
fi
